// src/App.js
import React, { useState } from 'react';
import { ThemeProvider } from './context/ThemeContext';
import { PlayerIdentityProvider } from './context/PlayerIdentityContext';
import LeagueSetupStep1 from './components/LeagueSetupStep1';
import LeagueSetupStep2 from './components/LeagueSetupStep2';
import Dashboard from './components/dashboard/Dashboard';
import {
  createLeague,
  createPlayers,
  createTeams,
  createMatches,
  saveInitialRankings,
} from './lib/db';
import { setActiveLeagueId, storeToken } from './lib/session';

function AppContent() {
  const [step, setStep] = useState(1);
  const [leagueSettings, setLeagueSettings] = useState(null);
  const [leagueData, setLeagueData] = useState(null);
  const [effectiveSettings, setEffectiveSettings] = useState(null);
  const [launching, setLaunching] = useState(false);
  // The player who launched — auto-logged-in without needing a code
  const [adminPlayer, setAdminPlayer] = useState(null);

  const handleStep1Next = (settings) => {
    setLeagueSettings(settings);
    setStep(2);
  };

  const handleLaunch = async (
    generatedLeague,
    finalSettings,
    adminName = '',
  ) => {
    setLaunching(true);

    // Helper: find the designated admin in a player list
    const findAdmin = (players) =>
      (adminName && players.find((p) => p.name === adminName)) || players[0];

    try {
      // ── Try to persist to Supabase ──────────────────────────
      const dbLeague = await createLeague(finalSettings);
      const leagueId = dbLeague.id;

      const dbPlayers = await createPlayers(
        leagueId,
        generatedLeague.seededParticipants.map((p) => ({
          ...p,
          isAdmin: adminName
            ? p.name === adminName
            : generatedLeague.seededParticipants.indexOf(p) === 0,
        })),
      );

      const admin = findAdmin(dbPlayers);
      if (admin?.sessionToken) storeToken(leagueId, admin.sessionToken);
      setAdminPlayer(admin);

      if (
        finalSettings.singlesOrDoubles === 'doubles' &&
        generatedLeague.seededParticipants[0]?.players
      ) {
        await createTeams(leagueId, generatedLeague.seededParticipants);
      }

      await createMatches(
        leagueId,
        generatedLeague.matches.map((m) => ({
          ...m,
          p1_player_id: m.p1?.id || null,
          p2_player_id: m.p2?.id || null,
        })),
      );

      await saveInitialRankings(
        leagueId,
        dbPlayers,
        finalSettings.singlesOrDoubles === 'doubles',
      );
      setActiveLeagueId(leagueId);

      setEffectiveSettings({ ...finalSettings, id: leagueId });
      setLeagueData({ ...generatedLeague, seededParticipants: dbPlayers });
    } catch (err) {
      // ── No DB / offline — run fully in-memory ───────────────
      console.warn(
        '[App] Supabase unavailable, running in-memory:',
        err.message,
      );

      // Give each participant a fake token so identity works locally
      const participants = generatedLeague.seededParticipants.map((p, i) => ({
        ...p,
        sessionToken: p.sessionToken || `local-${p.id}`,
        role: (adminName ? p.name === adminName : i === 0) ? 'admin' : 'player',
      }));

      const admin = findAdmin(participants);
      setAdminPlayer(admin);
      setEffectiveSettings({ ...finalSettings, id: null });
      setLeagueData({ ...generatedLeague, seededParticipants: participants });
    }

    setLaunching(false);
    setStep(3);
  };

  const activeSettings = effectiveSettings || leagueSettings;

  return (
    <div className="app">
      {step === 1 && (
        <LeagueSetupStep1
          onNext={handleStep1Next}
          initialSettings={leagueSettings}
        />
      )}
      {step === 2 && (
        <LeagueSetupStep2
          settings={leagueSettings}
          onLaunch={handleLaunch}
          onBack={() => setStep(1)}
          externalLaunching={launching}
        />
      )}
      {step === 3 && (
        // Pass adminPlayer so PlayerIdentityProvider can skip the PlayerPicker
        <PlayerIdentityProvider
          leagueId={activeSettings?.id}
          initialPlayer={adminPlayer}
        >
          <Dashboard settings={activeSettings} leagueData={leagueData} />
        </PlayerIdentityProvider>
      )}
    </div>
  );
}

function App() {
  return (
    <ThemeProvider>
      <AppContent />
    </ThemeProvider>
  );
}

export default App;
